import{_ as t,o as a,c as r,ag as i}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse(`{"title":"Parametres de l'entreprise","description":"","frontmatter":{},"headers":[],"relativePath":"fr/settings/company.md","filePath":"fr/settings/company.md"}`),s={name:"fr/settings/company.md"};function o(n,e,l,d,u,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="parametres-de-l-entreprise" tabindex="-1">Parametres de l&#39;entreprise <a class="header-anchor" href="#parametres-de-l-entreprise" aria-label="Permalink to &quot;Parametres de l&#39;entreprise&quot;">​</a></h1><p>Configurez les informations de votre entreprise, l&#39;image de marque, les parametres financiers par defaut et les fonctionnalites activees.</p><h2 id="acceder-aux-parametres" tabindex="-1">Acceder aux parametres <a class="header-anchor" href="#acceder-aux-parametres" aria-label="Permalink to &quot;Acceder aux parametres&quot;">​</a></h2><p>Naviguez vers <strong>Entreprise</strong> dans la barre laterale pour acceder a tous les parametres de l&#39;entreprise. Les parametres sont organises en sections.</p><h2 id="informations-de-l-entreprise" tabindex="-1">Informations de l&#39;entreprise <a class="header-anchor" href="#informations-de-l-entreprise" aria-label="Permalink to &quot;Informations de l&#39;entreprise&quot;">​</a></h2><h3 id="coordonnees-de-l-entreprise" tabindex="-1">Coordonnees de l&#39;entreprise <a class="header-anchor" href="#coordonnees-de-l-entreprise" aria-label="Permalink to &quot;Coordonnees de l&#39;entreprise&quot;">​</a></h3><ul><li><strong>Nom de l&#39;entreprise</strong> -- Le nom enregistre de votre entreprise (apparait sur tous les documents)</li><li><strong>Adresse</strong> -- Rue, code postal, ville, pays</li><li><strong>E-mail de contact</strong> -- Adresse e-mail professionnelle principale</li><li><strong>Telephone</strong> -- Numero de telephone professionnel</li></ul><h3 id="immatriculation" tabindex="-1">Immatriculation <a class="header-anchor" href="#immatriculation" aria-label="Permalink to &quot;Immatriculation&quot;">​</a></h3><ul><li><strong>Numero de TVA</strong> -- Votre numero d&#39;identification TVA (par ex., NL123456789B01)</li><li><strong>Chambre de Commerce</strong> -- Numero d&#39;immatriculation commerciale</li><li><strong>IBAN</strong> -- Compte bancaire pour recevoir les paiements</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>L&#39;autocompletion d&#39;adresse est disponible -- commencez a taper et selectionnez parmi les suggestions alimentees par Google Maps.</p></div><h2 id="image-de-marque" tabindex="-1">Image de marque <a class="header-anchor" href="#image-de-marque" aria-label="Permalink to &quot;Image de marque&quot;">​</a></h2><h3 id="logo" tabindex="-1">Logo <a class="header-anchor" href="#logo" aria-label="Permalink to &quot;Logo&quot;">​</a></h3><p>Telechargez le logo de votre entreprise pour l&#39;utiliser sur :</p><ul><li>Les PDF de factures et devis</li><li>Les communications par e-mail</li><li>Le portail client</li><li>La page publique d&#39;entreprise</li></ul><p>Formats acceptes : PNG, JPG, SVG. Utilisez une image haute resolution avec un fond transparent pour de meilleurs resultats.</p><h3 id="couleurs" tabindex="-1">Couleurs <a class="header-anchor" href="#couleurs" aria-label="Permalink to &quot;Couleurs&quot;">​</a></h3><p>Definissez votre couleur d&#39;accentuation de marque. Elle est utilisee sur :</p><ul><li>Les documents PDF</li><li>Les modeles d&#39;e-mail</li><li>Les pages accessibles aux clients</li></ul><h2 id="parametres-financiers-par-defaut" tabindex="-1">Parametres financiers par defaut <a class="header-anchor" href="#parametres-financiers-par-defaut" aria-label="Permalink to &quot;Parametres financiers par defaut&quot;">​</a></h2><h3 id="devise" tabindex="-1">Devise <a class="header-anchor" href="#devise" aria-label="Permalink to &quot;Devise&quot;">​</a></h3><p>Definissez votre devise par defaut (EUR par defaut). Elle s&#39;applique aux nouvelles factures et aux nouveaux devis.</p><h3 id="conditions-de-paiement" tabindex="-1">Conditions de paiement <a class="header-anchor" href="#conditions-de-paiement" aria-label="Permalink to &quot;Conditions de paiement&quot;">​</a></h3><p>Definissez le nombre de jours par defaut avant l&#39;echeance d&#39;une facture. Valeurs courantes :</p><ul><li><strong>14 jours</strong> -- Deux semaines</li><li><strong>30 jours</strong> -- Un mois</li><li><strong>60 jours</strong> -- Deux mois</li></ul><p>Vous pouvez modifier cela pour chaque facture individuellement.</p><h3 id="numerotation-des-factures" tabindex="-1">Numerotation des factures <a class="header-anchor" href="#numerotation-des-factures" aria-label="Permalink to &quot;Numerotation des factures&quot;">​</a></h3><p>Personnalisez la generation des numeros de facture :</p><ul><li><strong>Prefixe</strong> -- Texte avant le numero (par ex., <code>INV-</code>, <code>2024-</code>)</li><li><strong>Numero de depart</strong> -- Le premier numero de la sequence</li><li><strong>Incrementation automatique</strong> -- Les numeros augmentent automatiquement</li></ul><h2 id="activation-des-fonctionnalites" tabindex="-1">Activation des fonctionnalites <a class="header-anchor" href="#activation-des-fonctionnalites" aria-label="Permalink to &quot;Activation des fonctionnalites&quot;">​</a></h2><p>Activez ou desactivez les modules optionnels :</p><table tabindex="0"><thead><tr><th>Fonctionnalite</th><th>Description</th></tr></thead><tbody><tr><td><strong>Objets / Actifs</strong></td><td>Gestion de biens locatifs et d&#39;actifs</td></tr><tr><td><strong>Contrats</strong></td><td>Contrats de services et de location recurrents</td></tr><tr><td><strong>Projets</strong></td><td>Suivi du travail base sur des projets</td></tr><tr><td><strong>Devis</strong></td><td>Gestion des devis</td></tr><tr><td><strong>Autoliquidation</strong></td><td>Facturation B2B intra-UE</td></tr><tr><td><strong>Suggestions IA</strong></td><td>Recommandations de categorisation intelligentes</td></tr><tr><td><strong>Numerisation de recus</strong></td><td>Saisie de depenses par OCR</td></tr><tr><td><strong>Verification de texte</strong></td><td>Verification de la grammaire et de l&#39;orthographe</td></tr></tbody></table><p>Les modules desactives sont masques dans la navigation pour garder votre espace de travail epure.</p><h2 id="modele-pdf" tabindex="-1">Modele PDF <a class="header-anchor" href="#modele-pdf" aria-label="Permalink to &quot;Modele PDF&quot;">​</a></h2><p>Personnalisez la mise en page et l&#39;apparence de vos PDF generes :</p><ul><li>Positionnement des champs</li><li>Visibilite des informations</li><li>Police et taille</li><li>Placement du logo</li></ul><p>Accedez a l&#39;<strong>editeur PDF</strong> complet pour une personnalisation visuelle par glisser-deposer depuis Entreprise &gt; Editeur PDF.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>La personnalisation avancee du PDF necessite le plan <strong>Pro</strong> ou superieur.</p></div><h2 id="membres-de-l-equipe" tabindex="-1">Membres de l&#39;equipe <a class="header-anchor" href="#membres-de-l-equipe" aria-label="Permalink to &quot;Membres de l&#39;equipe&quot;">​</a></h2><p>Consultez et gerez votre equipe depuis la page de l&#39;entreprise. Voir <a href="/fr/settings/team">Gestion de l&#39;equipe</a> pour plus de details.</p>',39)])])}const h=t(s,[["render",o]]);export{m as __pageData,h as default};
